import json
import os


class ConfigLoader:
    def __init__(self, path):
        self.path = path
        self._cache = None

    def load(self):
        if self._cache is None:
            with open(self.path, "r", encoding="utf-8") as f:
                self._cache = json.load(f)
        return self._cache

    def reload(self):
        self._cache = None
        return self.load()

    def get(self, key, default=None):
        return self.load().get(key, default)

    # TODO: add YAML support once the ops team standardizes on it
    def exists(self):
        return os.path.isfile(self.path)
